# report_generator.py

from jinja2 import Environment, FileSystemLoader, select_autoescape, DictLoader

class ReportGenerator:
    def __init__(self, template_dir=None):
        if template_dir:
            loader = FileSystemLoader(template_dir)
        else:
            # fallback to default embedded templates
            loader = DictLoader({
                'base.html': BASE_TEMPLATE,
                'summary.html': SUMMARY_TEMPLATE,
                'detailed.html': DETAILED_TEMPLATE,
            })
        self.env = Environment(
            loader=loader,
            autoescape=select_autoescape(['html', 'xml'])
        )
    def render(self, template_name, data, thresholds=None, **extra_context):
        """
        Render a report.
        :param template_name: name of the template (e.g., 'summary.html')
        :param data: list of dicts representing rows
        :param thresholds: dict of column name -> threshold for highlighting
        :param extra_context: any other variables to pass to the template
        :return: rendered HTML string
        """
        tmpl = self.env.get_template(template_name)
        context = {
            'data': data,
            'thresholds': thresholds or {},
        }
        context.update(extra_context)
        return tmpl.render(**context)

# Templates as strings
BASE_TEMPLATE = """<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>{% block title %}Report{% endblock %}</title>
