        header, footer {background: #333; color: #fff; padding: 1em; text-align: center;}
        .content {padding: 2em;}
        table {border-collapse: collapse; width: 100%;}
        th, td {border: 1px solid #ddd; padding: 0.5em; text-align: left;}
        th {background: #f4f4f4;}
        .highlight {background-color: #ffdddd;}
    </style>
</head>
<body>
    <header>
        {% block header %}Report Header{% endblock %}
    </header>
    <div class="content">
        {% block content %}{% endblock %}
    </div>
    <footer>
        {% block footer %}Report Footer{% endblock %}
    </footer>
</body>
</html>
"""

SUMMARY_TEMPLATE = """{% extends "base.html" %}
{% block title %}Summary Report{% endblock %}
{% block header %}Summary Report - {{ report_date }}{% endblock %}
{% block content %}
<h2>Summary Table</h2>
<table>
    <thead>
        <tr>
            {% for col in columns %}
            <th>{{ col|capitalize }}</th>
            {% endfor %}
        </tr>
    </thead>
    <tbody>
        {% for row in data %}
        {% set highlight = false %}
        {% for col, threshold in thresholds.items() %}
            {% if row[col] is defined and row[col] > threshold %}
                {% set highlight = true %}
            {% endif %}
        {% endfor %}
        <tr class="{{ 'highlight' if highlight else '' }}">
            {% for col in columns %}
            <td>{{ row[col] }}</td>
            {% endfor %}
        </tr>
        {% endfor %}
    </tbody>
</table>
{% endblock %}
{% block footer %}Generated on {{ report_date }}{% endblock %}
"""

DETAILED_TEMPLATE = """{% extends "base.html" %}
{% block title %}Detailed Report{% endblock %}
{% block header %}Detailed Report - {{ report_date }}{% endblock %}
